define i32 @and_add_bool_no_fold(i32 %y) {
  %x = and i32 %y, 1
  %mask = add i32 -1, %x
  %res = and i32 %mask, %y
  ret i32 %res
}

define i32 @and_add_bool_to_select(i1 %x, i32 %y) {
  %val = zext i1 %x to i32
  %mask = add i32 -1, %val
  %res = and i32 %mask, %y
  ret i32 %res
}

define i64 @PR63321(ptr %ptr, i64 %c) {
  %val = load i8, ptr %ptr, align 1, !range !0
  %rhs = zext i8 %val to i64
  %mask = add i64 -1, %rhs
  %res = and i64 %mask, %c
  ret i64 %res
}

!0 = !{i8 0, i8 2}

